package main

import (
	"context"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/joho/godotenv"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/router"
	"github.com/ketang/flotsam/api/internal/server"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	// 1. Load .env (no-op if file is absent — dev convenience only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam api",
		"version", version.Version,
		"build_time", version.BuildTime,
		"env", cfg.Env,
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error
	}
	defer pool.Close()

	// 5. Initialize auth validator
	validator := auth.NewHMACValidator(cfg.JWTSecret)
	slog.Info("auth: using HS256 JWT validator")

	// 6. Build router
	r := router.New(router.Deps{
		Config:    cfg,
		Pool:      pool,
		Validator: validator,
	})

	// 7. Start HTTP server
	srv := server.New(cfg.Addr(), r)

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.Start(); err != nil {
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 8. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 9. Graceful shutdown
	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	slog.Info("server: shutting down", "timeout", cfg.ShutdownTimeout)
	if err := srv.Shutdown(shutdownCtx); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}
	slog.Info("server: shutdown complete")
}

package router

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strings"

	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/cors"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	flotsammiddleware "github.com/ketang/flotsam/api/internal/middleware"
	"github.com/ketang/flotsam/api/internal/version"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config    *config.Config
	Pool      *pgxpool.Pool
	Validator auth.Validator
	// River client will be added when flt-it8.3 is implemented.
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Global middleware (applied to every request)
	r.Use(flotsammiddleware.RequestID)
	r.Use(flotsammiddleware.Logging)
	r.Use(flotsammiddleware.Recovery)
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// CORS (if configured)
	if deps.Config.CORSOrigins != "" {
		origins := parseCORSOrigins(deps.Config.CORSOrigins)
		r.Use(cors.Handler(cors.Options{
			AllowedOrigins:   origins,
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type"},
			AllowCredentials: true,
			MaxAge:           300,
		}))
	}

	// Health endpoint — no auth
	r.Get("/health", healthHandler)

	// GraphQL endpoint — optional auth + rate limit
	r.Route("/graphql", func(r chi.Router) {
		r.Use(flotsammiddleware.OptionalAuth(deps.Validator))
		if deps.Config.RateLimitEnabled {
			rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitGraphQL)
			r.Use(rl.Limit)
		}
		r.Post("/", placeholderHandler("graphql"))
		r.Get("/", placeholderHandler("graphql"))
	})

	// MCP endpoint — mandatory auth + rate limit
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			r.Handle("/*", placeholderHandler("mcp"))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", placeholderHandler("upload"))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func placeholderHandler(name string) http.HandlerFunc {
	return func(w http.ResponseWriter, _ *http.Request) {
		http.Error(w, name+" endpoint not yet implemented", http.StatusNotImplemented)
	}
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

package config

import (
	"fmt"
	"log/slog"
	"os"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`
	JWTSecret   string `env:"JWT_SECRET,required"` //nolint:gosec // config field name, not a hardcoded secret

	S3Endpoint       string `env:"S3_ENDPOINT"`
	S3Bucket         string `env:"S3_BUCKET" envDefault:"flotsam-dev"`
	S3AccessKey      string `env:"S3_ACCESS_KEY"`
	S3SecretKey      string `env:"S3_SECRET_KEY"`
	S3Region         string `env:"S3_REGION" envDefault:"us-east-1"`
	S3ForcePathStyle bool   `env:"S3_FORCE_PATH_STYLE" envDefault:"false"`

	OpenAIAPIKey string `env:"OPENAI_API_KEY"`
	OllamaURL    string `env:"OLLAMA_URL"`

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"false"`

	MCPEnabled bool `env:"MCP_ENABLED" envDefault:"true"`

	RateLimitEnabled     bool `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int  `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int  `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitMCP         int  `env:"RATE_LIMIT_MCP" envDefault:"120"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return slog.Level(-8) // custom TRACE level
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
func (c *Config) LogHandler() slog.Handler {
	level := ParseLogLevel(c.LogLevel)
	opts := &slog.HandlerOptions{
		Level:     level,
		AddSource: c.Env == "development",
	}

	if c.LogFormat == "text" {
		return slog.NewTextHandler(os.Stderr, opts)
	}
	return slog.NewJSONHandler(os.Stderr, opts)
}

