func TestNew(t *testing.T) {
	t.Run("empty bucket returns error", func(t *testing.T) {
		_, err := New(Config{Bucket: ""})
		if err == nil {
			t.Fatal("expected error for empty bucket")
		}
	})

	t.Run("valid config succeeds", func(t *testing.T) {
		client, err := New(Config{
			Endpoint:       "http://localhost:9000",
			Bucket:         "test-bucket",
			AccessKey:      "minioadmin",
			SecretKey:      "minioadmin",
			Region:         "us-east-1",
			ForcePathStyle: true,
		})
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if client == nil {
			t.Fatal("expected non-nil client")
		}
		if client.bucket != "test-bucket" {
			t.Errorf("bucket = %q, want %q", client.bucket, "test-bucket")
		}
	})
}

func TestIntegrationRoundTrip(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	endpoint := os.Getenv("S3_ENDPOINT")
	if endpoint == "" {
		t.Skip("S3_ENDPOINT not set, skipping integration test")
	}

	accessKey := os.Getenv("S3_ACCESS_KEY")
	if accessKey == "" {
		accessKey = "minioadmin"
	}
	secretKey := os.Getenv("S3_SECRET_KEY")
	if secretKey == "" {
		secretKey = "minioadmin"
	}
	bucket := os.Getenv("S3_BUCKET")
	if bucket == "" {
		bucket = "flotsam-dev"
	}

	client, err := New(Config{
		Endpoint:       endpoint,
		Bucket:         bucket,
		AccessKey:      accessKey,
		SecretKey:      secretKey,
		Region:         "us-east-1",
		ForcePathStyle: true,
	})
	if err != nil {
		t.Fatalf("failed to create client: %v", err)
	}

	ctx := context.Background()
	ownerID := uuid.New()
	itemID := uuid.New()
	key := BookmarkKey(ownerID, itemID)
	content := []byte("<html><body>Hello, world!</body></html>")

	// Upload
	err = client.Upload(ctx, key, bytes.NewReader(content), "text/html")
	if err != nil {
		t.Fatalf("Upload failed: %v", err)
	}

	// Exists — should be true
	exists, err := client.Exists(ctx, key)
	if err != nil {
		t.Fatalf("Exists failed: %v", err)
	}
	if !exists {
		t.Fatal("expected object to exist after upload")
	}

	// Download
	rc, err := client.Download(ctx, key)
	if err != nil {
		t.Fatalf("Download failed: %v", err)
	}
	defer rc.Close()

	downloaded, err := io.ReadAll(rc)
	if err != nil {
		t.Fatalf("reading download body: %v", err)
	}
	if !bytes.Equal(downloaded, content) {
		t.Errorf("downloaded content mismatch: got %q, want %q", downloaded, content)
	}

	// PresignedURL — should return a non-empty URL
	url, err := client.PresignedURL(ctx, key, 60*time.Second)
	if err != nil {
		t.Fatalf("PresignedURL failed: %v", err)
	}
	if url == "" {
		t.Fatal("expected non-empty presigned URL")
	}

	// Delete
	err = client.Delete(ctx, key)
	if err != nil {
		t.Fatalf("Delete failed: %v", err)
	}

	// Exists — should be false
	exists, err = client.Exists(ctx, key)
	if err != nil {
		t.Fatalf("Exists after delete failed: %v", err)
	}
	if exists {
		t.Fatal("expected object to not exist after delete")
	}
}

