// SeedAll inserts all seed data into the database.
func SeedAll(ctx context.Context, pool *pgxpool.Pool) error {
	userIDs, err := SeedUsers(ctx, pool)
	if err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
	}

	for _, uid := range userIDs {
		if err := SeedItems(ctx, pool, uid); err != nil {
			return fmt.Errorf("testutil: seed all: %w", err)
		}
	}

	// Use the first user for MCP clients and audit log.
	clientIDs, err := SeedMCPClients(ctx, pool, userIDs[0])
	if err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
	}

	if err := SeedAuditLog(ctx, pool, userIDs[0], clientIDs[0]); err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
