// Command devtoken generates a JWT for local development and testing.
// It queries the database for the first user and mints a token using JWT_SECRET.
//
// Usage:
//
//	go run ./cmd/devtoken
//	go run ./cmd/devtoken --email ketan@example.com
//	go run ./cmd/devtoken --email ketan@example.com --expiry 720h
package main

import (
	"context"
	"flag"
	"fmt"
	"log/slog"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
	"github.com/joho/godotenv"

	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
)

func main() {
	email := flag.String("email", "", "user email (default: first user in DB)")
	expiry := flag.Duration("expiry", 720*time.Hour, "token expiry duration (default: 30 days)")
	flag.Parse()

	_ = godotenv.Load()

	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	if cfg.Env != "development" {
		fmt.Fprintln(os.Stderr, "error: devtoken only works when ENV=development")
		os.Exit(1)
	}

	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1)
	}
	defer pool.Close()

	// Find user
	var userID uuid.UUID
	var userEmail string
	var query string
	var args []any

	if *email != "" {
		query = `SELECT id, email FROM users WHERE email = $1 LIMIT 1`
		args = []any{*email}
	} else {
		query = `SELECT id, email FROM users ORDER BY created_at LIMIT 1`
	}

	if err := pool.QueryRow(ctx, query, args...).Scan(&userID, &userEmail); err != nil {
		slog.Error("user not found", "email", *email, "error", err)
		fmt.Fprintln(os.Stderr, "hint: run 'make api-seed' to create sample users")
		os.Exit(1)
	}

	// Mint JWT
	now := time.Now()
	claims := jwt.MapClaims{
		"uid":   userID.String(),
		"email": userEmail,
		"ctype": "cli",
		"iss":   "flotsam-devtoken",
		"iat":   now.Unix(),
		"exp":   now.Add(*expiry).Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signed, err := token.SignedString([]byte(cfg.JWTSecret))
	if err != nil {
		slog.Error("failed to sign token", "error", err)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "# Token for %s (%s), expires %s\n", userEmail, userID, now.Add(*expiry).Format(time.RFC3339))
	fmt.Fprintf(os.Stderr, "export FLOTSAM_TOKEN='%s'\n", signed)
	fmt.Print(signed)
}

